import { Store } from '../store';

describe('Store', () => {
  const createTestStore = () => {
    type State = { count: number };
    type Action = { type: string; payload?: number };

    const reducer = (state: State = { count: 0 }, action: Action): State => {
      if (action.type === 'INCREMENT') {
        return { count: state.count + 1 };
      }
      if (action.type === 'ADD') {
        return { count: state.count + (action.payload ?? 0) };
      }
      return state;
    };

    return Store.create({
      reducer: reducer as any,
      getInitialState: () => ({ count: 0 }) as any,
      machineID: 'test',
    });
  };

  describe('subscribe', () => {
    it('should call listeners when state changes', () => {
      const store = createTestStore();
      const listener = vi.fn();

      store.subscribe(listener);
      store.dispatch({ type: 'INCREMENT' });

      expect(listener).toHaveBeenCalledTimes(1);
    });

    it('should stop calling listener after unsubscribe', () => {
      const store = createTestStore();
      const listener = vi.fn();

      const unsubscribe = store.subscribe(listener);
      store.dispatch({ type: 'INCREMENT' });
      expect(listener).toHaveBeenCalledTimes(1);

      unsubscribe();
      store.dispatch({ type: 'INCREMENT' });
      expect(listener).toHaveBeenCalledTimes(1);
    });

    /**
     * FIX-001: Listener unsubscription during dispatch causes skipped listeners
     *
     * This test verifies that when a listener unsubscribes itself during
     * dispatch, all other listeners are still called correctly.
     *
     * Bug: The dispatch function iterates over currentListeners directly.
     * If a listener unsubscribes itself, splice() mutates the array while
     * being iterated, causing subsequent listeners to be skipped.
     */
    it('should call all listeners even when one unsubscribes itself during dispatch [FIX-001]', () => {
      const store = createTestStore();

      const callOrder: number[] = [];
      let unsubscribe1: () => void;

      const listener1 = vi.fn(() => {
        callOrder.push(1);
        // Listener 1 unsubscribes itself during dispatch
        unsubscribe1();
      });

      const listener2 = vi.fn(() => {
        callOrder.push(2);
      });

      const listener3 = vi.fn(() => {
        callOrder.push(3);
      });

      unsubscribe1 = store.subscribe(listener1);
      store.subscribe(listener2);
      store.subscribe(listener3);

      // Dispatch - all 3 listeners should be called
      store.dispatch({ type: 'INCREMENT' });

      expect(listener1).toHaveBeenCalledTimes(1);
      expect(listener2).toHaveBeenCalledTimes(1);
      expect(listener3).toHaveBeenCalledTimes(1);
      expect(callOrder).toEqual([1, 2, 3]);

      // Second dispatch - only listeners 2 and 3 should be called
      callOrder.length = 0;
      store.dispatch({ type: 'INCREMENT' });

      expect(listener1).toHaveBeenCalledTimes(1); // Still 1, not subscribed anymore
      expect(listener2).toHaveBeenCalledTimes(2);
      expect(listener3).toHaveBeenCalledTimes(2);
      expect(callOrder).toEqual([2, 3]);
    });

    it('should handle multiple listeners unsubscribing during same dispatch [FIX-001]', () => {
      const store = createTestStore();

      const callOrder: number[] = [];
      let unsubscribe1: () => void;
      let unsubscribe2: () => void;

      const listener1 = vi.fn(() => {
        callOrder.push(1);
        unsubscribe1();
      });

      const listener2 = vi.fn(() => {
        callOrder.push(2);
        unsubscribe2();
      });

      const listener3 = vi.fn(() => {
        callOrder.push(3);
      });

      const listener4 = vi.fn(() => {
        callOrder.push(4);
      });

      unsubscribe1 = store.subscribe(listener1);
      unsubscribe2 = store.subscribe(listener2);
      store.subscribe(listener3);
      store.subscribe(listener4);

      store.dispatch({ type: 'INCREMENT' });

      expect(listener1).toHaveBeenCalledTimes(1);
      expect(listener2).toHaveBeenCalledTimes(1);
      expect(listener3).toHaveBeenCalledTimes(1);
      expect(listener4).toHaveBeenCalledTimes(1);
      expect(callOrder).toEqual([1, 2, 3, 4]);
    });
  });

  describe('dispatch', () => {
    it('should throw on non-object action', () => {
      const store = createTestStore();

      expect(() => store.dispatch('INCREMENT' as any)).toThrow(
        'Actions must be plain objects',
      );
    });

    it('should throw on action without type', () => {
      const store = createTestStore();

      expect(() => store.dispatch({ payload: 1 } as any)).toThrow(
        'Actions may not have an undefined "type" property',
      );
    });

    it('should update state correctly', () => {
      const store = createTestStore();

      store.dispatch({ type: 'INCREMENT' });
      expect(store.getState().count).toBe(1);

      store.dispatch({ type: 'ADD', payload: 5 });
      expect(store.getState().count).toBe(6);
    });
  });
});

