import { devLog, setLogMode } from '../logs';

describe('logs', () => {
  beforeEach(() => {
    setLogMode('development');
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  describe('devLog', () => {
    it('should log string messages with console.trace in development', () => {
      const traceSpy = vi.spyOn(console, 'trace').mockImplementation(() => {});

      devLog('test message', { extra: 'data' });

      expect(traceSpy).toHaveBeenCalledWith('test message', { extra: 'data' });
    });

    it('should not log in production mode', () => {
      setLogMode('production');
      const traceSpy = vi.spyOn(console, 'trace').mockImplementation(() => {});

      devLog('test message');

      expect(traceSpy).not.toHaveBeenCalled();
    });

    /**
     * FIX-002: devLog should NOT throw when receiving an Error object
     *
     * Current behavior: throws the error, crashing the app
     * Expected behavior: logs the error to console.error without throwing
     *
     * This is critical because developers may use devLog(error) in catch
     * blocks to log caught errors, expecting it to behave like console.error.
     */
    it('should log Error objects without throwing [FIX-002]', () => {
      const errorSpy = vi.spyOn(console, 'error').mockImplementation(() => {});
      const error = new Error('test error');

      // Should NOT throw
      expect(() => devLog(error)).not.toThrow();

      // Should log to console.error
      expect(errorSpy).toHaveBeenCalled();
    });

    it('should handle Error objects in catch blocks safely [FIX-002]', () => {
      const errorSpy = vi.spyOn(console, 'error').mockImplementation(() => {});
      let caughtError: Error | null = null;

      try {
        throw new Error('original error');
      } catch (e) {
        caughtError = e as Error;
        // This should NOT re-throw the error
        devLog(caughtError);
      }

      // Code after catch should execute
      expect(caughtError).not.toBeNull();
      expect(errorSpy).toHaveBeenCalled();
    });

    it('should not log Error objects in production mode [FIX-002]', () => {
      setLogMode('production');
      const errorSpy = vi.spyOn(console, 'error').mockImplementation(() => {});
      const error = new Error('test error');

      expect(() => devLog(error)).not.toThrow();
      expect(errorSpy).not.toHaveBeenCalled();
    });
  });
});

