      }
      // FIX-007: Return plain object instead of hybrid to avoid V8 deoptimization
      return isSliceKey
        ? { state: stateRef.current, actions: actionsRef.current }
        : stateRef.current;
    });
  }

  return {
    useSelector,
    useMachine,
  };
}

