import { getTypeOf } from '../helpers/typeof';
import { InferType, TypeDefinition, TypeDefinitionString } from './infer-type';
import { createType } from './schema';

/**
 * Checks if value matches type
 * @param value
 * @param definition
 *
 * @example
 *  isType(new Date('BANANA'), 'date') // => false; value is an invalid date;
 *  isType(1, 'number') // => true; value is a number
 *  isType(undefined, 'number?') // => true; value matches type `number?`
 *  isType(undefined, 'number') // => false; value should be a number
 */
export function isType<Type extends TypeDefinitionString>(
  value: unknown,
  definition: Type,
): value is InferType<Type> {
  return createType(definition).isValid(value);
}

/**
 * Asserts that value is of type `Type`
 * @param value
 * @param definition
 * @param parentFunction
 * @param customMessage
 *
 *  @example
 *  const x = ['banana'] as unknown;
 *  assertType('string[]', x)
 *  console.log(x) // typescript now infers x as string[]
 *
 *  @example:
 *  // will throw 'Expected value to match type "string[]"; found an invalid "Number" instead.',
 *  assertType('string[]', 1)
 */
export function invariantType<Type extends TypeDefinition>(
  definition: Type,
  value: unknown,
  parentFunction?: Function,
  /**
   * Custom message
   * Accepts replacements `$typename`, `$originalMessage` and `$definition`.
   */
  customMessage = `Expected value to match type "$definition"; found an invalid "$typename" instead.`
): asserts value is InferType<Type> {
  try {
    createType(definition as never).parse(value);
  } catch (e: any) {
    const originalMessage = typeof e.message === 'string' ? e.message : '';

    let newMessage = customMessage.replace(
      /\$(definition|typename|originalMessage)/g,
      substring => {
        switch (substring) {
          case '$definition': {
            return definition;
          }
          case '$typename': {
            return getTypeOf(value);
          }
          case '$originalMessage': {
            return originalMessage;
          }
          default: {
            return substring;
          }
        }
      },
    );

    e.message = newMessage;
    if (parentFunction) Error.captureStackTrace(e, parentFunction);
    throw e;
  }
}

