import { assert, IsExact } from 'conditional-type-checks';

import {
  assertObject,
  assertValues,
  getProperty,
  isObject,
  keyBy,
  objectEntries,
  objectHasOwnProperty,
  objectKeys,
  objectValues,
  reduceObject,
  requireAll,
  setProperties,
  setProperty,
} from '../object-utils';
import { capitalize } from '../string-utils';
import { Paths } from '../type-utils';

describe('ObjectUtils', () => {
  const user = {
    id: 123,
    name: 'Philip',
    address: {
      street: 'Precious Avenue',
      number: '350',
    },
  };

  test('Infer Paths correctly', () => {
    type SUT = Paths<typeof user>;

    type Expected =
      | 'id'
      | 'name'
      | 'address'
      | 'address.number'
      | 'address.street';

    assert<IsExact<Expected, SUT>>(true);
  });

  describe('getValue()', () => {
    it('should return existing value', () => {
      const number = getProperty(user, 'address.number');

      assert<IsExact<typeof number, string>>(true);

      expect(number).toBe(user.address.number);
    });

    it('should return undefined for non existing value', () => {
      const number = getProperty(user, 'address.DO_NOT_EXIST', true);

      expect(number).toBe(undefined);
    });
  });

  describe('getValue strict', () => {
    it('should return existing value', () => {
      const number = getProperty(user, 'address.number');

      assert<IsExact<typeof number, string>>(true);

      expect(number).toBe(user.address.number);
    });

    it('should throw for undefined values', () => {
      expect(() => {
        getProperty(user, 'address.FOO_BAR');
      }).toThrow(
        'Expected property `address.FOO_BAR` to not be falsy; found undefined instead.',
      );
    });

    it('should check against empty strings', () => {
      expect(() => {
        getProperty({ a: { b: '' } }, 'a.b');
      }).toThrow('Expected property `a.b` to not be falsy; found "" instead.');
    });

    it('should check against 0', () => {
      expect(() => {
        getProperty({ a: { b: 0 } }, 'a.b');
      }).toThrow('Expected property `a.b` to not be falsy; found 0 instead.');

      expect(() => {
        getProperty({ a: { b: -0 } }, 'a.b');
      }).toThrow('Expected property `a.b` to not be falsy; found 0 instead.');
    });
  });

  describe('keys', () => {
    it('should return typed object keys', () => {
      const userKeys = objectKeys(user);
      assert<IsExact<typeof userKeys, ('id' | 'name' | 'address')[]>>(true);
      expect(userKeys).toEqual([
        'id',
        'name',
        'address',
      ]);
    });
  });

  describe('isUnknownRecord', () => {
    it('should return true for Object instance', () => {
      expect(isObject(user)).toEqual(true);
    });

    it('should return false for null', () => {
      expect(isObject(null)).toEqual(false);
    });

    it('should return false for non Object instance', () => {
      expect(isObject(new Map())).toEqual(false);
    });
  });

  describe('assertValues', () => {
    it('should pass without falsy values', () => {
      const sut = {
        a: 1,
        b: '2',
        c: ['3'] as string[] | undefined,
      };
      assertValues(sut);

      assert<
        IsExact<
          typeof sut,
          {
            a: number;
            b: string;
            c: string[]; // asserted c as not undefined
          }
        >
      >(true);
    });

    it('should throw on falsy values', () => {
      const sut = {
        a: 1,
        b: '',
        c: undefined as string[] | undefined,
      };

      const check = () => {
        assertValues(sut);
        return sut;
      };

      assert<
        IsExact<
          ReturnType<typeof check>,
          {
            a: number;
            b: string;
            c: string[]; // asserted c as not undefined
          }
        >
      >(true);

      expect(check).toThrow(
        'Expected property `b` to not be falsy; found "" instead.',
      );

      expect(check).toThrow(
        ' Expected property `c` to not be falsy; found undefined instead.',
      );
    });
  });

  describe('objectEntries', () => {
    it('should return typed object entries', () => {
      const entries = objectEntries(user);
      type Expected = (
        | ['id', number]
        | ['name', string]
        | [
            'address',
            {
              street: string;
              number: string;
            },
          ]
      )[];

      assert<IsExact<typeof entries, Expected>>(true);

      expect(entries).toEqual([
        [
          'id',
          123,
        ],
        [
          'name',
          'Philip',
        ],
        [
          'address',
          {
            street: 'Precious Avenue',
            number: '350',
          },
        ],
      ]);
    });
  });

  describe('objectMap', () => {
    it('should map() correctly', () => {
      const object = {
        NAME: 'ZAZ',
        AGE: 21,
        '5': 'NUM',
      } as const;
      const sut = objectMap(object);
      type O = typeof object;
      type Expected = (['NAME', 'ZAZ'] | ['AGE', 21] | ['5', 'NUM'])[] & O;
      assert<IsExact<typeof sut, Expected>>(true);
      const keys = sut.map(el => [
        el[0],
        el[1],
      ]);
      expect(keys).toEqual([
        [
          '5',
          'NUM',
        ],
        [
          'NAME',
          'ZAZ',
        ],
        [
          'AGE',
          21,
        ],
      ]);
    });

    it('should have properties', () => {
      const object = {
        NAME: 'ZAZ',
        AGE: 21,
        '5': 'NUM',
      } as const;
      const sut = objectMap(object);
      expect(sut.AGE).toEqual(21);
      expect(sut[0]).toEqual([
        '5',
        'NUM',
      ]);
    });

    it('should assign properties', () => {
      const object = {
        NAME: 'ZAZ',
        AGE: 21,
        '5': 'NUM',
      } as const;
      const sut = objectMap(object);
      Object.assign(sut, { a: 1 });
      expect(sut).toEqual({
        '5': 'NUM',
        AGE: 21,
        NAME: 'ZAZ',
        a: 1,
      });
    });

    it('should extend as object', () => {
      const object = {
        NAME: 'ZAZ',
        AGE: 21,
        '5': 'NUM',
      } as const;
      const map = objectMap(object);
      const sut = {
        a: 1,
        ...map,
      };
      expect(JSON.stringify(sut)).toEqual(
        '{"5":"NUM","a":1,"NAME":"ZAZ","AGE":21}',
      );
    });

    it('should extend as array', () => {
      const object = {
        NAME: 'ZAZ',
        AGE: 21,
        '5': 'NUM',
      } as const;
      const map = objectMap(object);
      const sut = [
        ...map,
        0,
        1,
        2,
        3,
        4,
        5,
        6,
      ];
      expect(JSON.stringify(sut)).toEqual(
        '[["5","NUM"],["NAME","ZAZ"],["AGE",21],0,1,2,3,4,5,6]',
      );
    });
  });

  describe('objectValues', () => {
    it('should return typed object values', () => {
      const values = objectValues(user);
      type Expected = (
        | string
        | number
        | {
            street: string;
            number: string;
          }
      )[];
      assert<IsExact<typeof values, Expected>>(true);
      expect(values).toEqual([
        123,
        'Philip',
        {
          street: 'Precious Avenue',
          number: '350',
        },
      ]);
    });
  });

  describe('objectHasOwnProperty', () => {
    it('should correctly check for own properties', () => {
      expect(objectHasOwnProperty(user, 'name')).toBe(true);
      expect(objectHasOwnProperty(user.address, 'street')).toBe(true);
    });

    it('should return false for inherited properties', () => {
      expect(objectHasOwnProperty(user, 'toString')).toBe(false);
    });

    it('should return false for non-existent properties', () => {
      expect(objectHasOwnProperty(user, 'age')).toBe(false);
    });

    it('should act as a type guard', () => {
      const key: string = 'name';
      if (objectHasOwnProperty(user, key)) {
        // key is now 'id' | 'name' | 'address'
        assert<IsExact<typeof key, 'id' | 'name' | 'address'>>(true);
        expect(user[key]).toBe('Philip');
      }
    });
  });

  describe('setProperty', () => {
    it('should set a value on a nested path', () => {
      const userClone = JSON.parse(JSON.stringify(user));
      setProperty(userClone, 'address.street', 'New Avenue');
      expect(userClone.address.street).toBe('New Avenue');
    });

    it('should return the mutated object', () => {
      const userClone = { ...user };
      const result = setProperty(userClone, 'name', 'John');
      expect(result).toBe(userClone);
      expect(result.name).toBe('John');
    });
  });

  describe('setProperties', () => {
    it('should set multiple values on different paths', () => {
      const userClone = JSON.parse(JSON.stringify(user));
      const result = setProperties(userClone, {
        name: 'Peter',
        'address.number': '999',
      });
      expect(result.name).toBe('Peter');
      expect(result.address.number).toBe('999');
    });
  });

  describe('requireAll', () => {
    it('should return the object if no falsy values are present', () => {
      const sut = {
        a: 1,
        b: '2',
        c: ['3'] as string[] | undefined,
      };
      const result = requireAll(sut);

      assert<
        IsExact<
          typeof result,
          {
            a: number;
            b: string;
            c: string[];
          }
        >
      >(true);
      expect(result).toBe(sut);
    });

    it('should throw an error if falsy values are present', () => {
      const sut = {
        a: 1,
        b: '',
        c: undefined,
      };
      expect(() => requireAll(sut)).toThrow(
        'Expected property `b` to not be falsy; found "" instead. Expected property `c` to not be falsy; found undefined instead.',
      );
    });
  });

  describe('keyBy', () => {
    const arr = [
      {
        id: 'a',
        value: 1,
      },
      {
        id: 'b',
        value: 2,
      },
    ];

    it('should create an object keyed by the specified property', () => {
      const result = keyBy(arr, item => item.id);
      expect(result).toEqual({
        a: {
          id: 'a',
          value: 1,
        },
        b: {
          id: 'b',
          value: 2,
        },
      });
    });

    it('should handle duplicate keys, keeping the last one', () => {
      const duplicates = [
        ...arr,
        {
          id: 'a',
          value: 3,
        },
      ];
      const result = keyBy(duplicates, item => item.id);
      expect(result.a).toEqual({
        id: 'a',
        value: 3,
      });
    });

    it('should call onDuplicate callback when a key is repeated', () => {
      const onDuplicate = vi.fn();
      const duplicates = [
        ...arr,
        {
          id: 'a',
          value: 3,
        },
      ];
      keyBy(duplicates, item => item.id, onDuplicate);
      expect(onDuplicate).toHaveBeenCalledTimes(1);
      expect(onDuplicate).toHaveBeenCalledWith('a', {
        id: 'a',
        value: 3,
      });
    });
  });

  describe('reduceObject', () => {
    it('reduce', () => {
      const sut = reduceObject(
        {
          a: 1,
          b: 2,
          c: 3,
        },
        ([key, value]) => {
          return {
            [`Foo${capitalize(key)}`]: value,
          };
        },
      );

      expect(sut).toEqual({
        FooA: 1,
        FooB: 2,
        FooC: 3,
      });
    });

    it('should handle larger objects efficiently', () => {
      // Create object with 100 entries
      const input: Record<string, number> = {};
      for (let i = 0; i < 100; i++) {
        input[`key${i}`] = i;
      }

      const result = reduceObject(input, ([key, value]) => ({
        [`doubled_${key}`]: value * 2,
      }));

      expect(Object.keys(result).length).toBe(100);
      expect(result['doubled_key0']).toBe(0);
      expect(result['doubled_key50']).toBe(100);
      expect(result['doubled_key99']).toBe(198);
    });

    it('should handle empty objects', () => {
      const result = reduceObject({}, ([key, value]) => ({ [key]: value }));
      expect(result).toEqual({});
    });
  });

  describe('assertObject', () => {
    test('assertObject', () => {
      expect(() => assertObject(1)).toThrow(
        'Expected value to be an object; found Number instead.',
      );
    });
  });
});
